const STATIC_ASSETS = [
    '/static/css/main.css',
    '/static/js/app.js',
];

// Only cache requests whose path is in the explicit static allowlist or
// starts with /static/ (images, fonts, etc.).  Authenticated pages and API
// responses are never stored so they cannot leak to a subsequent user.
function isStaticAsset(url) {
    const pathname = new URL(url).pathname;
    return STATIC_ASSETS.includes(pathname) || pathname.startsWith('/static/');
}

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => cache.addAll(STATIC_ASSETS))
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    const { method, url } = event.request;
    if (method !== 'GET') {
        // For write requests, try network first; if offline, return a queued response
        event.respondWith(
            fetch(event.request.clone()).catch(() => {
                return new Response(
                    JSON.stringify({ queued: true, message: 'Your change has been queued and will sync when online.' }),
                    { status: 202, headers: { 'Content-Type': 'application/json' } }
                );
            })
        );
        return;
    }

    // Non-static paths (authenticated pages, API endpoints) go network-only.
    // Never cache them — prevents cross-user data leakage on shared workstations.
    if (!isStaticAsset(url)) {
        event.respondWith(fetch(event.request));
        return;
    }

    // Static assets: stale-while-revalidate
    event.respondWith(
        caches.match(event.request).then(cached => {
            const fetchPromise = fetch(event.request).then(response => {
                if (response.ok) {
                    const clone = response.clone();
                    caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                }
                return response;
            }).catch(() => cached);
            return cached || fetchPromise;
        })
    );
});

// Wipe all caches on demand (sent by the client after logout).
self.addEventListener('message', event => {
    if (event.data && event.data.type === 'CLEAR_CACHE') {
        event.waitUntil(
            caches.keys().then(keys => Promise.all(keys.map(k => caches.delete(k))))
        );
    }
});
"}

